        val nodeBeforeAnnotations = modifierListRoot.treeParent.treePrev as? PsiWhiteSpace
        // If there is no whitespace before the annotation, the annotation is the first
        // text in the file
        val newLineWithIndent = nodeBeforeAnnotations?.text ?: "\n"
        return if (newLineWithIndent.contains('\n')) {
            // Make sure we only insert a single newline
            newLineWithIndent.substring(newLineWithIndent.lastIndexOf('\n'))
        } else {
            newLineWithIndent
        }
    }

    private fun getNewlineWithIndentForTypeArgumentList(node: ASTNode): String {
        // Find the type argument list parent
        var current: ASTNode? = node
        while (current != null && current.elementType != TYPE_ARGUMENT_LIST) {
            current = current.treeParent
        }

        // Find the whitespace before the type argument list to determine base indentation
        val typeArgumentList = current
        val whitespaceBefore = typeArgumentList?.prevLeaf { it.isWhiteSpace() }

        val baseIndent = if (whitespaceBefore != null && whitespaceBefore.text.contains('\n')) {
            // Extract indentation from whitespace before type argument list
            whitespaceBefore.text.substring(whitespaceBefore.text.lastIndexOf('\n'))
        } else {
            "\n"
        }

        // Add one level of indentation (4 spaces is standard)
        // TODO: This should ideally use IndentConfig, but for now use a simple approach
        return baseIndent + "    "
    }
}"}

