{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/AnnotationRuleTypeArgumentListTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Tests for annotation formatting in type argument lists.
 * Issue: https://github.com/pinterest/ktlint/issues/673
 */
class AnnotationRuleTypeArgumentListTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given a single annotation in a type argument list then do not report a violation`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid FooDto>,
            )

            annotation class Valid
            class FooDto
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single annotation with parameter in a type argument list then do not report a violation`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Suppress("test") FooDto>,
            )

            class FooDto
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given multiple annotations on same line in a type argument list then report violations`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )

            annotation class Valid
            annotation class NotNull
            class FooDto
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 20, "Annotation must be placed on separate line", canBeAutoCorrected = false),
                LintViolation(2, 27, "Annotation must be placed on separate line", canBeAutoCorrected = false),
            )
    }

    @Test
    fun `Given multiple annotations on same line in a type argument list with Map then report violations`() {
        val code =
            """
            data class FooRequestDto(
                val data: Map<@Valid @NotNull String, @Valid @NotNull Int>,
            )

            annotation class Valid
            annotation class NotNull
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 19, "Annotation must be placed on separate line", canBeAutoCorrected = false),
                LintViolation(2, 26, "Annotation must be placed on separate line", canBeAutoCorrected = false),
                LintViolation(2, 43, "Annotation must be placed on separate line", canBeAutoCorrected = false),
                LintViolation(2, 50, "Annotation must be placed on separate line", canBeAutoCorrected = false),
            )
    }

    @Test
    fun `Given multiple annotations already on separate lines in a type argument list then do not report violations`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<
                    @Valid
                    @NotNull
                    FooDto
                >,
            )

            annotation class Valid
            annotation class NotNull
            class FooDto
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given annotations with parameters on same line in a type argument list then do not report violations`() {
        val code =
            """
            val aProperty: Map<@Ann("test") Int, @JvmSuppressWildcards(true) (String) -> Int?>

            annotation class Ann(val s: String)
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

